SELECT
FROM journey_record WHERE enabled = TRUE AND user_id = #{userId}
AND ( LOWER(company) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(position_name) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(business_direction) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(interview_content) LIKE CONCAT('%', LOWER(#{keyword}), '%') )
AND status = #{status}
AND result = #{result}
ORDER BY updated_at DESC LIMIT 300

